diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..6da6d8f84e0f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1339,7 +1340,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   }

   // Look through and with a negative power of 2 mask on V1 or V2. This
-  // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 1
+  // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 
   // is aligned to the mask and A + 1 >= |Mask|. This pattern corresponds to a
   // contiguous range check, which can be folded into an addition and compare.
   // The same applies for `(x != A) && ((x & Mask) != A + 1)`.
@@ -1367,8 +1368,81 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

-  if (V1 != V2)
+  // Handle the case where one comparison is on V and the other is on (V & Mask)
+  if (V1 != V2) {
+    // Check if V2 is V1 & Mask
+    const APInt *Mask = nullptr;
+    Value *X;
+    if (match(V2, m_And(m_Specific(V1), m_APInt(Mask)))) {
+      // For (V & Mask) == C, V can be C or (C | ~Mask) or C + k*(~Mask+1)
+      // We need to check if all possible values are within the other range
+      APInt MaskVal = *Mask;
+      APInt NotMask = ~MaskVal;
+      
+      // Compute the two extremal values with the same low bits
+      APInt Val1 = *C2;
+      APInt Val2 = *C2 | NotMask;
+      
+      // Check if both values satisfy the other comparison
+      ConstantRange CR1 = ConstantRange::makeExactICmpRegion(Pred1, *C1);
+      if (Offset1)
+        CR1 = CR1.subtract(*Offset1);
+      
+      bool Val1InRange = CR1.contains(Val1);
+      bool Val2InRange = CR1.contains(Val2);
+      
+      if (IsAnd) {
+        // For AND, if both possible values are in range, the mask check implies the range check
+        if (Val1InRange && Val2InRange) {
+          return ICmp2;
+        }
+        // If neither value is in range, the AND is always false
+        if (!Val1InRange && !Val2InRange) {
+          return ConstantInt::getBool(ICmp1->getType(), false);
+        }
+      } else {
+        // For OR, if at least one value is in range, the mask check may be redundant
+        if (Val1InRange || Val2InRange) {
+          // The OR is true if either condition is true
+          // If both values are in range, the mask check is redundant
+          if (Val1InRange && Val2InRange) {
+            return ICmp1;
+          }
+        }
+      }
+    }
+    // Also check symmetric case: V1 is V2 & Mask
+    else if (match(V1, m_And(m_Specific(V2), m_APInt(Mask)))) {
+      APInt MaskVal = *Mask;
+      APInt NotMask = ~MaskVal;
+      
+      APInt Val1 = *C1;
+      APInt Val2 = *C1 | NotMask;
+      
+      ConstantRange CR2 = ConstantRange::makeExactICmpRegion(Pred2, *C2);
+      if (Offset2)
+        CR2 = CR2.subtract(*Offset2);
+      
+      bool Val1InRange = CR2.contains(Val1);
+      bool Val2InRange = CR2.contains(Val2);
+      
+      if (IsAnd) {
+        if (Val1InRange && Val2InRange) {
+          return ICmp1;
+        }
+        if (!Val1InRange && !Val2InRange) {
+          return ConstantInt::getBool(ICmp1->getType(), false);
+        }
+      } else {
+        if (Val1InRange || Val2InRange) {
+          if (Val1InRange && Val2InRange) {
+            return ICmp2;
+          }
+        }
+      }
+    }
     return nullptr;
+  }

   ConstantRange CR1 =
       MatchedAnd1
@@ -1419,6 +1493,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

